        let mgr = McpManager::new(McpRegistry::new());
        let err = mgr
            .oauth_complete_callback("unknown-state", "code")
            .await
            .expect_err("expected unknown state to fail");
        assert!(matches!(
            err,
            Error::Manager(McpManagerError::OAuthStateNotFound)
        ));
    }
}

