        assert_eq!(result, "http://other-host:4000/mcp/msg?sid=xyz");
    }

    #[test]
    fn test_parse_endpoint_event_relative_path_with_base_path() {
        let body = "event: endpoint\ndata: /mcp/message?sessionId=test-session\n\n";
